def apply_rs_promotion(axis_result, rs_features, rs_score):
    if rs_score < 0.40:
        return axis_result
    if not axis_result.is_rs_sensitive:
        return axis_result
    if axis_result.tier == "VALIDATED":
        return axis_result
    if axis_result.tier == "STRONG":
        return axis_result
    if has_independent_evidence(axis_result):
        axis_result.tier = "STRONG"
        axis_result.promotion_source = "rs_promotion"
    return axis_result
